def search(nums):
    if len(nums) == 0:
        return -1
    i, j = 0, len(nums) - 1
    while i < j:
        mid = i + (j - i) // 2
        if mid % 2 == 1:
            mid -= 1
        if nums[mid] == nums[mid + 1]:
            if nums[mid] != nums[mid - 1]:
                i = mid + 1
            else:
                j = mid
        else:
            j = mid - 1

