def bell(n):
    global bell_number
    if n == 0:
        bell_number = 1
    elif n == 1:
        bell_number = 1
    elif n == 2:
        bell_number = 2
    else:
        for i in range(0, n):
            bell_number = bell_number + i * bell(n - i - 1)

    return bell_number

