def sequence(n):
    if n == 1:
        return 1
    sequence_dict = {1: 1, 2: 1}
    count, index1, index2 = 3, 1, 1
    while count <= n:
        new_value = sequence_dict[index1] + sequence_dict[index2]
        if count <= n:
            sequence_dict[count] = new_value
            count += 1
        index1, index2 = index2 - 1, index1 -1
    return sequence_dict[n]

