import math

def is_undulating(num):
    ''' check if the given num is undulating '''
    num = round(num)
    digits = [math.floor(num)]

    while num != 0:
        num /= 10
        digits.append(math.floor(num))

    is_undulating = True
    for d in digits:
        count = 0
        for value in digits:
            if value == d:
                count += 1

        if count == 1 or count == 4:
            is_undulating = False
            break

    return is_undulating

